import{_ as r,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"z.ai-Integration: Funktionsgrenzen erklärt | Antigravity-Manager","description":"Beherrschen Sie die z.ai-Integrationsgrenzen von Antigravity Tools. Erfahren Sie mehr über Anforderungsrouting, dispatch_mode-Loadbalancing, Modellmapping, Header-Sicherheitsrichtlinien sowie MCP-Reverse-Proxy und Einschränkungen.","frontmatter":{"title":"z.ai-Integration: Funktionsgrenzen erklärt | Antigravity-Manager","sidebarTitle":"z.ai-Grenzen Schnellreferenz","subtitle":"z.ai-Integration: Funktionsgrenzen erklärt","description":"Beherrschen Sie die z.ai-Integrationsgrenzen von Antigravity Tools. Erfahren Sie mehr über Anforderungsrouting, dispatch_mode-Loadbalancing, Modellmapping, Header-Sicherheitsrichtlinien sowie MCP-Reverse-Proxy und Einschränkungen.","tags":["z.ai","MCP","Claude","Funktionsgrenzen"],"prerequisite":["/de/lbjlaq/Antigravity-Manager/start/getting-started/","/de/lbjlaq/Antigravity-Manager/platforms/mcp/"],"order":3},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"de/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),n={name:"de/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function o(d,e,l,s,c,u){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="funktionsgrenzen-der-z-ai-integration-implementiert-vs-explizit-nicht-implementiert" tabindex="-1">Funktionsgrenzen der z.ai-Integration (Implementiert vs. Explizit nicht implementiert) <a class="header-anchor" href="#funktionsgrenzen-der-z-ai-integration-implementiert-vs-explizit-nicht-implementiert" aria-label="Permalink to &quot;Funktionsgrenzen der z.ai-Integration (Implementiert vs. Explizit nicht implementiert)&quot;">​</a></h1><p>Diese Dokumentation erklärt nur die „Grenzen&quot; der z.ai-Integration in Antigravity Tools – nicht die „Anbindung&quot;. Wenn Sie feststellen, dass eine bestimmte Funktion nicht funktioniert, vergleichen Sie sie hier zuerst: Ist sie nicht aktiviert, nicht konfiguriert oder gar nicht implementiert?</p><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Beurteilen, was Sie von z.ai erwarten können: was „implementiert&quot; ist und was in der Dokumentation „explizit nicht gemacht&quot; wurde</li><li>Verstehen, welche Endpunkte von z.ai betroffen sind (und welche überhaupt nicht beeinflusst werden)</li><li>Quellcode-/Dokumentationsnachweise für jede Schlussfolgerung mit GitHub-Zeilennummern-Links anzeigen –便于 eigene Überprüfung</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie haben z.ai möglicherweise bereits in Antigravity Tools aktiviert, stoßen aber bei der Nutzung auf folgende Fragen:</p><ul><li>Warum werden einige Anforderungen über z.ai geleitet, andere überhaupt nicht?</li><li>Können MCP-Endpunkte als „vollständiger MCP-Server&quot; betrachtet werden?</li><li>Entsprechen die im UI sichtbaren Schalter tatsächlich der tatsächlichen Implementierung?</li></ul><h2 id="was-ist-z-ai-integration-in-diesem-projekt" tabindex="-1">Was ist z.ai-Integration (in diesem Projekt)? <a class="header-anchor" href="#was-ist-z-ai-integration-in-diesem-projekt" aria-label="Permalink to &quot;Was ist z.ai-Integration (in diesem Projekt)?&quot;">​</a></h2><p><strong>z.ai-Integration</strong> ist in Antigravity Tools ein optionaler „Upstream-Provider + MCP-Erweiterung&quot;. Sie übernimmt nur unter bestimmten Bedingungen Claude-Protokollanforderungen und bietet MCP Search/Reader Reverse-Proxy sowie einen minimalen Vision MCP integrierten Server; sie ist keine vollständige Protokoll- und vollständige Fähigkeitsersatzlösung.</p><div class="info custom-block"><p class="custom-block-title">Ein Merksatz</p><p>Sie können z.ai als „optionalen Upstream für Claude-Anforderungen + eine Gruppe von schaltbaren MCP-Endpunkten&quot; betrachten – nicht als „alle Fähigkeiten von z.ai vollständig übertragen&quot;.</p></div><h2 id="implementiert-stabil-verfugbar-basierend-auf-quellcode" tabindex="-1">Implementiert: Stabil verfügbar (basierend auf Quellcode) <a class="header-anchor" href="#implementiert-stabil-verfugbar-basierend-auf-quellcode" aria-label="Permalink to &quot;Implementiert: Stabil verfügbar (basierend auf Quellcode)&quot;">​</a></h2><h3 id="_1-nur-das-claude-protokoll-wird-uber-z-ai-geleitet-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Nur das Claude-Protokoll wird über z.ai geleitet (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-nur-das-claude-protokoll-wird-uber-z-ai-geleitet-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Nur das Claude-Protokoll wird über z.ai geleitet (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>Das Upstream-Forwarding von z.ai Anthropic erfolgt nur im z.ai-Zweig des Claude-Handlers:</p><ul><li><code>POST /v1/messages</code>: Wenn <code>use_zai=true</code> ist, wird <code>forward_anthropic_json(...)</code> aufgerufen, um die JSON-Anforderung an den z.ai Anthropic-kompatiblen Endpunkt weiterzuleiten</li><li><code>POST /v1/messages/count_tokens</code>: Wenn z.ai aktiviert ist, wird ebenfalls weitergeleitet; andernfalls wird der Platzhalter <code>{input_tokens:0, output_tokens:0}</code> zurückgegeben</li></ul><p>Nachweise:</p><ul><li>z.ai-Zweigauswahl und Forwarding-Einstieg: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai-Zweig für count_tokens und Platzhalter-Rückgabe: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Implementierung des z.ai Anthropic-Forwarding: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">Wie ist „Antwort-Streaming&quot; zu verstehen?</p><p><code>forward_anthropic_json</code> leitet den Upstream-Antwortkörper als <code>bytes_stream()</code>-Stream an den Client weiter, ohne SSE zu parsen (siehe Response-Aufbau in <code>providers/zai_anthropic.rs</code>).</p></div><h3 id="_2-die-„tatsachliche-bedeutung-des-dispatch-modus-dispatch-mode" tabindex="-1">2) Die „tatsächliche Bedeutung&quot; des Dispatch-Modus (dispatch_mode) <a class="header-anchor" href="#_2-die-„tatsachliche-bedeutung-des-dispatch-modus-dispatch-mode" aria-label="Permalink to &quot;2) Die „tatsächliche Bedeutung&quot; des Dispatch-Modus (dispatch_mode)&quot;">​</a></h3><p><code>dispatch_mode</code> bestimmt, ob <code>/v1/messages</code> über z.ai geleitet wird:</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>Was passiert</th><th>Nachweis</th></tr></thead><tbody><tr><td><code>off</code></td><td>z.ai niemals verwenden</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>Alle Claude-Anforderungen werden über z.ai geleitet</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Nur wenn der Google-Pool nicht verfügbar ist (0 Konten oder „keine verfügbaren Konten&quot;), wird z.ai verwendet</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>z.ai als „zusätzlichen 1 Slot&quot; in das Round-Robin einbeziehen (keine Garantie für Treffer)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Häufiges Missverständnis bei pooled</p><p><code>pooled</code> bedeutet nicht „z.ai + Google-Kontenpool gemeinsam nutzen und stabil nach Gewicht splitten&quot;. Der Code schreibt explizit „no strict guarantees&quot; – im Grunde ist es ein Round-Robin-Slot (nur wenn <code>slot == 0</code> wird z.ai verwendet).</p></div><h3 id="_3-modellzuordnung-wie-claude-modellnamen-zu-z-ai-glm-werden" tabindex="-1">3) Modellzuordnung: Wie Claude-Modellnamen zu z.ai glm-* werden? <a class="header-anchor" href="#_3-modellzuordnung-wie-claude-modellnamen-zu-z-ai-glm-werden" aria-label="Permalink to &quot;3) Modellzuordnung: Wie Claude-Modellnamen zu z.ai glm-* werden?&quot;">​</a></h3><p>Vor dem Forwarding zu z.ai wird, wenn der Anforderungskörper ein <code>model</code>-Feld enthält, dieses umgeschrieben:</p><ol><li>Exakte Übereinstimmung mit <code>proxy.zai.model_mapping</code> (unterstützt gleichzeitig Originalzeichenfolge und lower-case Key)</li><li>Präfix <code>zai:&lt;model&gt;</code>: Entferne <code>zai:</code> direkt</li><li><code>glm-*</code>: Bleibt unverändert</li><li>Nicht <code>claude-*</code>: Bleibt unverändert</li><li><code>claude-*</code> und enthält <code>opus/haiku</code>: Abbildung auf <code>proxy.zai.models.opus/haiku</code>; andernfalls standardmäßig <code>sonnet</code></li></ol><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-header-sicherheitsrichtlinien-beim-forwarding-vermeidung-des-leaks-lokaler-proxy-keys" tabindex="-1">4) Header-Sicherheitsrichtlinien beim Forwarding (Vermeidung des Leaks lokaler Proxy-Keys) <a class="header-anchor" href="#_4-header-sicherheitsrichtlinien-beim-forwarding-vermeidung-des-leaks-lokaler-proxy-keys" aria-label="Permalink to &quot;4) Header-Sicherheitsrichtlinien beim Forwarding (Vermeidung des Leaks lokaler Proxy-Keys)&quot;">​</a></h3><p>Beim Upstream-Forwarding von z.ai werden nicht alle Header „ unverändert&quot; mitgenommen, sondern zwei Schutzschichten implementiert:</p><ul><li>Nur eine kleine Auswahl von Header wird durchgelassen (z. B. <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>Der API-Key von z.ai wird in den Upstream injiziert (Priorisierung der vom Client verwendeten Authentifizierungsmethode: <code>x-api-key</code> oder <code>Authorization: Bearer ...</code>)</li></ul><p>Nachweise:</p><ul><li>Header-Whitelist: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>Injektion von z.ai auth: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="implementiert-mcp-search-reader-reverse-proxy-vision-integriert" tabindex="-1">Implementiert: MCP (Search/Reader Reverse-Proxy + Vision integriert) <a class="header-anchor" href="#implementiert-mcp-search-reader-reverse-proxy-vision-integriert" aria-label="Permalink to &quot;Implementiert: MCP (Search/Reader Reverse-Proxy + Vision integriert)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-reverse-proxy-zum-mcp-endpunkt-von-z-ai" tabindex="-1">1) MCP Search/Reader: Reverse-Proxy zum MCP-Endpunkt von z.ai <a class="header-anchor" href="#_1-mcp-search-reader-reverse-proxy-zum-mcp-endpunkt-von-z-ai" aria-label="Permalink to &quot;1) MCP Search/Reader: Reverse-Proxy zum MCP-Endpunkt von z.ai&quot;">​</a></h3><p>Lokale Endpunkte und Upstream-Adressen sind fest codiert:</p><table tabindex="0"><thead><tr><th>Lokaler Endpunkt</th><th>Upstream-Adresse</th><th>Schalter</th><th>Nachweis</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 ist kein „Netzwerkproblem&quot;</p><p>Solange <code>proxy.zai.mcp.enabled=false</code> oder das entsprechende <code>web_search_enabled/web_reader_enabled=false</code>, geben diese Endpunkte direkt 404 zurück.</p></div><p>Nachweise:</p><ul><li>MCP-Gesamtschalter und z.ai Key-Validierung: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Routenregistrierung: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-ein-„minimaler-streamable-http-mcp-integrierter-server" tabindex="-1">2) Vision MCP: Ein „minimaler Streamable HTTP MCP&quot; integrierter Server <a class="header-anchor" href="#_2-vision-mcp-ein-„minimaler-streamable-http-mcp-integrierter-server" aria-label="Permalink to &quot;2) Vision MCP: Ein „minimaler Streamable HTTP MCP&quot; integrierter Server&quot;">​</a></h3><p>Vision MCP ist kein Reverse-Proxy, sondern eine lokale integrierte Implementierung:</p><ul><li>Endpunkt: <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> unterstützt: <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code> gibt SSE keepalive zurück (erfordert initialisierte Session)</li><li><code>DELETE</code> beendet Session</li></ul><p>Nachweise:</p><ul><li>Handler-Haupteinstieg und Methoden-Dispatch: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Implementierung von <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code>: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Position des „minimalen Implementierung&quot; von Vision MCP: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-werkzeugset-8-stuck-und-dateigroßenbegrenzung" tabindex="-1">3) Vision MCP Werkzeugset (8 Stück) und Dateigrößenbegrenzung <a class="header-anchor" href="#_3-vision-mcp-werkzeugset-8-stuck-und-dateigroßenbegrenzung" aria-label="Permalink to &quot;3) Vision MCP Werkzeugset (8 Stück) und Dateigrößenbegrenzung&quot;">​</a></h3><p>Die Werkzeugliste stammt aus <code>tool_specs()</code>:</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>Lokale Dateien werden ausgelesen und als <code>data:&lt;mime&gt;;base64,...</code> codiert, gleichzeitig gibt es harte Begrenzungen:</p><ul><li>Bild上限 5 MB (<code>image_source_to_content(..., 5)</code>)</li><li>Video上限 8 MB (<code>video_source_to_content(..., 8)</code>)</li></ul><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="explizit-nicht-implementiert-nicht-zu-erwarten-basierend-auf-dokumentationsangaben-und-implementierungsdetails" tabindex="-1">Explizit nicht implementiert / Nicht zu erwarten (basierend auf Dokumentationsangaben und Implementierungsdetails) <a class="header-anchor" href="#explizit-nicht-implementiert-nicht-zu-erwarten-basierend-auf-dokumentationsangaben-und-implementierungsdetails" aria-label="Permalink to &quot;Explizit nicht implementiert / Nicht zu erwarten (basierend auf Dokumentationsangaben und Implementierungsdetails)&quot;">​</a></h2><h3 id="_1-z-ai-usage-budget-uberwachung-usage-budget-nicht-implementiert" tabindex="-1">1) z.ai Usage/Budget-Überwachung (usage/budget) nicht implementiert <a class="header-anchor" href="#_1-z-ai-usage-budget-uberwachung-usage-budget-nicht-implementiert" aria-label="Permalink to &quot;1) z.ai Usage/Budget-Überwachung (usage/budget) nicht implementiert&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> schreibt explizit „not implemented yet&quot;. Das bedeutet:</p><ul><li>Sie können nicht erwarten, dass Antigravity Tools Usage/Budget-Abfragen oder Warnungen für z.ai bereitstellt</li><li>Quota-Protection wird auch nicht automatisch Budget/Usage-Daten von z.ai lesen</li></ul><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-ist-kein-vollstandiger-mcp-server" tabindex="-1">2) Vision MCP ist kein vollständiger MCP-Server <a class="header-anchor" href="#_2-vision-mcp-ist-kein-vollstandiger-mcp-server" aria-label="Permalink to &quot;2) Vision MCP ist kein vollständiger MCP-Server&quot;">​</a></h3><p>Vision MCP ist derzeit als „nur ausreichend für Werkzeugaufrufe&quot; minimale Implementierung positioniert: prompts/resources, resumability, streamed tool output usw. sind noch nicht implementiert.</p><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-spiegelt-nicht-die-echte-modellliste-von-z-ai" tabindex="-1">3) <code>/v1/models/claude</code> spiegelt nicht die echte Modellliste von z.ai <a class="header-anchor" href="#_3-v1-models-claude-spiegelt-nicht-die-echte-modellliste-von-z-ai" aria-label="Permalink to &quot;3) `/v1/models/claude` spiegelt nicht die echte Modellliste von z.ai&quot;">​</a></h3><p>Die von diesem Endpunkt zurückgegebene Modellliste stammt aus lokaler integrierter Zuordnung und benutzerdefinierter Zuordnung (<code>get_all_dynamic_models</code>), ohne <code>/v1/models</code> des z.ai-Upstreams abzurufen.</p><p>Nachweise:</p><ul><li>Handler: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Logik der Listengenerierung: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="konfigurationsfelder-schnellreferenz-z-ai-bezogen" tabindex="-1">Konfigurationsfelder Schnellreferenz (z.ai-bezogen) <a class="header-anchor" href="#konfigurationsfelder-schnellreferenz-z-ai-bezogen" aria-label="Permalink to &quot;Konfigurationsfelder Schnellreferenz (z.ai-bezogen)&quot;">​</a></h2><p>Die z.ai-Konfiguration befindet sich unter <code>ProxyConfig.zai</code> und umfasst folgende Felder:</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (exakte Übereinstimmungsüberschreibungen)</li><li><code>models.{opus,sonnet,haiku}</code> (Claude-Familie Standardzuordnung)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>Standardwerte (base_url / Standardmodelle) befinden sich ebenfalls in derselben Datei:</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>Nachweis: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li>z.ai übernimmt derzeit nur Claude-Protokoll (<code>/v1/messages</code> + <code>count_tokens</code>); andere Protokollendpunkte sind nicht „automatisch über z.ai&quot;</li><li>MCP Search/Reader ist Reverse-Proxy; Vision MCP ist lokale minimale Implementierung, kein vollständiger MCP-Server</li><li>Die Modellliste von <code>/v1/models/claude</code> stammt aus lokaler Zuordnung und repräsentiert nicht die echten Modelle des z.ai-Upstreams</li></ul><hr><h2 id="nachster-kurs" tabindex="-1">Nächster Kurs <a class="header-anchor" href="#nachster-kurs" aria-label="Permalink to &quot;Nächster Kurs&quot;">​</a></h2><blockquote><p>Im nächsten Kurs lernen wir <strong><a href="./../../changelog/release-notes/">Versionsverlauf</a></strong>.</p></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Erweitern, um Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>z.ai Standard base_url / Standardmodelle</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code> Wahllogik, ob über z.ai geleitet wird</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>z.ai Modellzuordnungsregeln (map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision Werkzeugliste und Einschränkungen (tool_specs + Dateigröße + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>',76)])])}const g=r(n,[["render",o]]);export{m as __pageData,g as default};
